import{_ as i,o as e,c as o,a4 as a}from"./chunks/framework.BhEBm8_q.js";const h=JSON.parse('{"title":"打印机无联网状态下的多人共享方案","description":"","frontmatter":{},"headers":[],"relativePath":"docs/局域网连接打印机.md","filePath":"docs/局域网连接打印机.md"}'),r={name:"docs/局域网连接打印机.md"};function t(n,l,s,d,c,p){return e(),o("div",null,[...l[0]||(l[0]=[a('<h1 id="打印机无联网状态下的多人共享方案" tabindex="-1">打印机无联网状态下的多人共享方案 <a class="header-anchor" href="#打印机无联网状态下的多人共享方案" aria-label="Permalink to “打印机无联网状态下的多人共享方案”">​</a></h1><p>当打印机无法联网时，可通过「主机有线连接+局域网共享」实现多人使用，老旧打印机也适用。</p><h2 id="一、主设备-连接打印机的电脑-设置" tabindex="-1">一、主设备（连接打印机的电脑）设置 <a class="header-anchor" href="#一、主设备-连接打印机的电脑-设置" aria-label="Permalink to “一、主设备（连接打印机的电脑）设置”">​</a></h2><ol><li><p><strong>基础连接测试</strong></p><p>用USB数据线连接打印机与主机，确保主机可正常打印（建议打印测试页验证）。</p></li><li><p><strong>开启打印机共享</strong></p><ul><li>找到「控制面板 → 设备和打印机」，右键目标打印机 → 「打印机属性」。</li><li>切换至「共享」选项卡，勾选「共享这台打印机」，可自定义共享名称。</li></ul></li><li><p><strong>配置网络共享权限</strong></p><ul><li>打开「控制面板 → 网络和共享中心 → 更改高级共享设置」。</li><li>启用以下选项： <ul><li>网络发现（选择「启用网络发现」）</li><li>文件和打印机共享（选择「启用文件和打印机共享」）</li><li>密码保护（选择「关闭密码保护共享」）。</li></ul></li><li>保存设置。</li></ul></li><li><p><strong>记录主机信息</strong></p><ul><li>打开「此电脑 → 右键属性」，复制「设备名称」（如<code>DESKTOP-XXX</code>），供其他设备连接使用。</li></ul></li></ol><h2 id="二、其他设备-需共享打印机的电脑-设置" tabindex="-1">二、其他设备（需共享打印机的电脑）设置 <a class="header-anchor" href="#二、其他设备-需共享打印机的电脑-设置" aria-label="Permalink to “二、其他设备（需共享打印机的电脑）设置”">​</a></h2><ol><li><p><strong>添加Windows凭证</strong></p><ul><li>打开「控制面板 → 凭证管理器 → Windows凭证 → 添加Windows凭证」。</li><li>网络地址填写：<code>\\\\设备名称</code>（例如<code>\\\\DESKTOP-XXX</code>），用户名：GUEST /密码为空（无密码可留空）。</li></ul></li><li><p><strong>确保网络一致</strong></p><p>连接与主机相同的WiFi或局域网。</p></li><li><p><strong>访问共享打印机</strong></p><ul><li>按<code>Win + R</code>，输入<code>\\\\设备名称</code>（如<code>\\\\DESKTOP-XXX</code>），回车。</li><li>右键弹出的共享打印机 → 「连接」，按提示安装驱动即可。</li></ul></li></ol><h2 id="完成效果" tabindex="-1">完成效果 <a class="header-anchor" href="#完成效果" aria-label="Permalink to “完成效果”">​</a></h2><p>其他设备会显示连接的打印机名称：<code>{设备名称}上的{打印机名称}</code>，可直接用于打印。</p>',8)])])}const u=i(r,[["render",t]]);export{h as __pageData,u as default};
